```json
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "Reviewer Summarization Widget Schema",
  "description": "Data contract for the Reviewer Summarization widget. Contains three analysis sections: (1) overall reviewer summary at audit level — compliance, issues, closure, coverage, (2) auditor execution duration summary — timeline adherence, and (3) auditor efficiency rating — quantified efficiency score.",
  "type": "object",
  "required": [
    "meta",
    "overallReviewerSummary",
    "auditorExecutionDurationSummary",
    "auditorEfficiencyRating"
  ],
  "additionalProperties": false,
  "properties": {
    "meta": {
      "type": "object",
      "description": "Metadata identifying the audit schedule and execution context for this payload.",
      "required": [
        "generatedAt",
        "scheduleId",
        "auditId",
        "mainAuditName",
        "auditType",
        "auditeeName",
        "auditorName",
        "currentExecutionStatus"
      ],
      "additionalProperties": false,
      "properties": {
        "generatedAt": {
          "type": "string",
          "format": "date-time",
          "description": "ISO 8601 timestamp when this payload was generated."
        },
        "scheduleId": {
          "type": "string",
          "description": "Unique identifier for the main audit schedule (MainAuditScheduleId)."
        },
        "auditId": {
          "type": "string",
          "description": "Unique identifier for the main audit (MainAuditId)."
        },
        "mainAuditName": {
          "type": "string",
          "description": "Display name of the main audit (MainAuditName)."
        },
        "auditType": {
          "type": "string",
          "description": "Type of audit (e.g. Branch Audit, Process Audit) — AuditTypeName."
        },
        "auditeeName": {
          "type": "string",
          "description": "Name of the auditee entity being audited."
        },
        "auditorName": {
          "type": "string",
          "description": "Name of the auditor who executed the audit."
        },
        "currentExecutionStatus": {
          "type": "string",
          "description": "Current execution status of the audit schedule (ExecutionStatus)."
        }
      }
    },
    "overallReviewerSummary": {
      "type": "object",
      "description": "Section 1 — Overall Reviewer Summary at Audit Level. Provides a consolidated view of audit completion status, compliance score, issue exposure (total, open, high-risk), closure rate, audit coverage, and risk distribution to help the reviewer assess audit quality.",
      "required": [
        "description",
        "currentExecutionStatus",
        "complianceScorePct",
        "auditRating",
        "totalIssues",
        "openIssues",
        "highAndZtIssues",
        "highIssues",
        "zeroToleranceIssues",
        "closedIssues",
        "closureRatePct",
        "totalAppliedCheckpoints",
        "totalCompletedCheckpoints",
        "coveragePct"
      ],
      "additionalProperties": false,
      "properties": {
        "description": {
          "type": "string",
          "description": "Explanation of what this section represents — consolidated audit-level summary covering compliance, issues, closure status, coverage, and risk distribution for reviewer assessment."
        },
        "currentExecutionStatus": {
          "type": "string",
          "description": "Current execution status of the audit schedule (e.g. 'In Progress', 'Submitted', 'In Review', 'Finalized'). Source: ExecutionStatus."
        },
        "complianceScorePct": {
          "anyOf": [
            {
              "type": "number"
            },
            {
              "type": "string",
              "enum": [
                ""
              ]
            }
          ],
          "description": "Overall compliance score for this audit. Formula: AchievedScore ÷ DenominatorScore × 100, rounded to 1 decimal. Or use AchievedPercentage directly from backend. Empty string if not yet available."
        },
        "auditRating": {
          "anyOf": [
            {
              "type": "string",
              "minLength": 1
            },
            {
              "type": "string",
              "enum": [
                ""
              ]
            }
          ],
          "description": "Overall quality rating assigned at finalization (e.g. 'Satisfactory', 'Needs Improvement', 'Unsatisfactory'). Source: AuditRating from backend. Empty string if the audit has not yet been rated."
        },
        "totalIssues": {
          "type": "integer",
          "description": "Total number of issues (all risk levels combined) identified in the current audit. Source: count of IssueId for this MainAuditId."
        },
        "openIssues": {
          "type": "integer",
          "description": "Count of issues that are still open — i.e. IssueStatus NOT IN ('Closed', 'Complied'). These require reviewer attention."
        },
        "highAndZtIssues": {
          "type": "integer",
          "description": "Combined count of critical-severity issues. Formula: count of IssueId where RiskLevel IN ('High', 'Zero Tolerance'). Key input for audit quality assessment."
        },
        "highIssues": {
          "type": "integer",
          "description": "Count of issues where RiskLevel = 'High'. Part of the High + ZT split."
        },
        "zeroToleranceIssues": {
          "type": "integer",
          "description": "Count of issues where RiskLevel = 'Zero Tolerance'. Part of the High + ZT split."
        },
        "closedIssues": {
          "type": "integer",
          "description": "Count of issues where IssueStatus = 'Closed' in the current audit."
        },
        "closureRatePct": {
          "anyOf": [
            {
              "type": "number"
            },
            {
              "type": "string",
              "enum": [
                ""
              ]
            }
          ],
          "description": "Percentage of total issues that have been closed. Formula: closedIssues ÷ totalIssues × 100, rounded to 1 decimal. Higher value = better remediation progress. Empty string if totalIssues = 0."
        },
        "totalAppliedCheckpoints": {
          "type": "integer",
          "description": "Total applicable checkpoints for this audit after filtering. Denominator for coveragePct. Source: TotalNoofAppliedCheckPoint."
        },
        "totalCompletedCheckpoints": {
          "type": "integer",
          "description": "Total checkpoints actually audited/executed by the auditor. Must be ≤ totalAppliedCheckpoints. Source: TotalNoOfCheckpointAudited."
        },
        "coveragePct": {
          "type": "number",
          "description": "Audit scope coverage. Formula: totalCompletedCheckpoints ÷ totalAppliedCheckpoints × 100, rounded to 1 decimal. ≥95% = Fully Covered; 80–94% = Substantially Covered; <80% = Incomplete."
        }
      }
    },
    "auditorExecutionDurationSummary": {
      "type": "object",
      "description": "Section 2 — Auditor Execution Duration Summary. Calculates how many days the auditor took to execute and submit the audit, compared against the planned timeline, to help the reviewer evaluate auditor efficiency and schedule adherence.",
      "required": [
        "description",
        "executionDurationDays",
        "plannedAuditDurationDays",
        "durationDifferenceDays",
        "submissionDelayDays",
        "auditStartDelayDays",
        "currentExecutionStatus"
      ],
      "additionalProperties": false,
      "properties": {
        "description": {
          "type": "string",
          "description": "Explanation of what this section represents — auditor execution timeline analysis covering actual vs planned duration, submission delay, and start delay."
        },
        "executionDurationDays": {
          "anyOf": [
            {
              "type": "number"
            },
            {
              "type": "string",
              "enum": [
                ""
              ]
            }
          ],
          "description": "Actual number of days the auditor spent executing the audit. Formula: ScheduleSubmittedAt − ScheduleStartedAt (in days). Empty string if either date is unavailable."
        },
        "plannedAuditDurationDays": {
          "anyOf": [
            {
              "type": "number"
            },
            {
              "type": "string",
              "enum": [
                ""
              ]
            }
          ],
          "description": "Originally planned audit window in days. Formula: AuditEndDate − AuditStartDate. Empty string if either date is unavailable."
        },
        "durationDifferenceDays": {
          "anyOf": [
            {
              "type": "number"
            },
            {
              "type": "string",
              "enum": [
                ""
              ]
            }
          ],
          "description": "Execution overrun or underrun vs plan. Formula: executionDurationDays − plannedAuditDurationDays. Positive = audit took longer than planned (overrun); negative = completed faster than planned. Empty string if either duration is unavailable."
        },
        "submissionDelayDays": {
          "anyOf": [
            {
              "type": "number"
            },
            {
              "type": "string",
              "enum": [
                ""
              ]
            }
          ],
          "description": "Delay between planned audit end and actual submission. Formula: ScheduleSubmittedAt − AuditEndDate (in days). Positive = submitted after planned end date (late); negative = submitted before planned end date (early). Empty string if either date is unavailable."
        },
        "auditStartDelayDays": {
          "anyOf": [
            {
              "type": "number"
            },
            {
              "type": "string",
              "enum": [
                ""
              ]
            }
          ],
          "description": "Delay between planned audit start and actual start. Formula: ScheduleStartedAt − AuditStartDate (in days). Positive = auditor started after the planned date (late start); 0 = on time; negative = started early. Empty string if either date is unavailable."
        },
        "currentExecutionStatus": {
          "type": "string",
          "description": "Current execution status of the audit schedule at the time this payload was generated (e.g. 'In Progress', 'Submitted', 'Accepted', 'Finalized'). Source: ExecutionStatus."
        }
      }
    },
    "auditorEfficiencyRating": {
      "type": "object",
      "description": "Section 3 — Auditor Efficiency Rating. Provides a quantified efficiency metric based on planned vs actual execution duration to help the reviewer assess auditor performance.",
      "required": [
        "description",
        "plannedDurationDays",
        "actualDurationDays",
        "efficiencyScorePct",
        "efficiencyRating"
      ],
      "additionalProperties": false,
      "properties": {
        "description": {
          "type": "string",
          "description": "Explanation of what this section represents — auditor efficiency scoring based on planned vs actual audit duration."
        },
        "plannedDurationDays": {
          "anyOf": [
            {
              "type": "number"
            },
            {
              "type": "string",
              "enum": [
                ""
              ]
            }
          ],
          "description": "Originally planned audit window in days. Formula: AuditEndDate − AuditStartDate. Repeated from Section 2 for self-containment. Empty string if either date is unavailable."
        },
        "actualDurationDays": {
          "anyOf": [
            {
              "type": "number"
            },
            {
              "type": "string",
              "enum": [
                ""
              ]
            }
          ],
          "description": "Actual number of days the auditor spent executing the audit. Formula: ScheduleSubmittedAt − ScheduleStartedAt. Repeated from Section 2 for self-containment. Empty string if either date is unavailable."
        },
        "efficiencyScorePct": {
          "anyOf": [
            {
              "type": "number"
            },
            {
              "type": "string",
              "enum": [
                ""
              ]
            }
          ],
          "description": "Auditor efficiency score. Formula: (plannedDurationDays ÷ actualDurationDays) × 100, rounded to 1 decimal. Value >100 means auditor was faster than planned; <100 means slower. Empty string if either duration is unavailable or actualDurationDays = 0."
        },
        "efficiencyRating": {
          "anyOf": [
            {
              "type": "string",
              "minLength": 1
            },
            {
              "type": "string",
              "enum": [
                ""
              ]
            }
          ],
          "description": "Categorical efficiency rating. 'Efficient' when actualDurationDays ≤ plannedDurationDays; 'Moderate' when delay ≤ 2 days; 'Delayed' when delay > 2 days. Empty string if durations are unavailable."
        }
      }
    }
  }
}
```
